// Daily scheduled agenda
const current = dv.current();
const terminalStatuses = new Set(['complete', 'completed', 'done', 'wont-do']);
const dateFormats = [moment.ISO_8601, 'YYYY-MM-DD HH:mm:ss', 'YYYY-MM-DD', 'dddd, MMMM Do YYYY', 'ddd, MMM D YYYY'];
const archivePathPattern = /(^|\/)(99 Archive|Archive|System\/Archive)(\/|$)/i;
const toMoment = (value) => {
  if (!value) return null;
  if (moment.isMoment(value)) return value.clone();
  if (typeof value === 'string') {
    const parsed = moment(value, dateFormats, true);
    if (parsed.isValid()) return parsed;
    const fallback = moment(value);
    return fallback.isValid() ? fallback : null;
  }
  if (typeof value.toISO === 'function') {
    const iso = value.toISO();
    if (iso) {
      const parsed = moment(iso);
      if (parsed.isValid()) return parsed;
    }
  }
  if (typeof value.ts === 'number') {
    const parsed = moment(value.ts);
    if (parsed.isValid()) return parsed;
  }
  if (value instanceof Date) {
    const parsed = moment(value);
    return parsed.isValid() ? parsed : null;
  }
  const parsed = moment(String(value));
  return parsed.isValid() ? parsed : null;
};
const normalizeDay = (value) => {
  const parsed = toMoment(value);
  return parsed ? parsed.format('YYYY-MM-DD') : null;
};
const sortValue = (value) => {
  const parsed = toMoment(value);
  return parsed ? parsed.valueOf() : Number.MAX_SAFE_INTEGER;
};
const collectTags = (page) => {
  const tags = new Set();
  for (const tag of Array.from(page?.file?.etags ?? [])) tags.add(String(tag).replace(/^#/, '').toLowerCase());
  const directTags = page?.tags;
  if (Array.isArray(directTags)) {
    for (const tag of directTags) tags.add(String(tag).replace(/^#/, '').toLowerCase());
  } else if (directTags) {
    tags.add(String(directTags).replace(/^#/, '').toLowerCase());
  }
  return tags;
};
const isArchivedPage = (page) => {
  const path = String(page?.file?.path || '');
  if (archivePathPattern.test(path)) return true;
  if (String(page?.status ?? '').trim().toLowerCase() === 'archived') return true;
  return page?.archived === true;
};
const cleanTaskText = (text) => String(text ?? '').replace(/\s*\[[^\]]+::[^\]]*\]/g, '').trim();
const openFile = (path) => (event) => {
  event.preventDefault();
  app.workspace.openLinkText(path, current.file.path, false);
};
const dayKey = normalizeDay(current.scheduled) || normalizeDay(current.file?.name);
dv.container.empty();
if (!dayKey) {
  dv.paragraph('No scheduled day found on this note.');
} else {
  const items = [];
  const seen = new Set();
  for (const page of dv.pages().array()) {
    if (!page?.file?.path) continue;
    if (isArchivedPage(page)) continue;
    const pagePath = page.file.path;
    const taskMatches = [];
    for (const task of Array.from(page.file.tasks ?? [])) {
      if (normalizeDay(task.scheduled ?? task.due ?? null) !== dayKey) continue;
      const taskLabel = cleanTaskText(task.text);
      const taskKey = `task:${pagePath}:${task.line ?? taskLabel}`;
      if (seen.has(taskKey)) continue;
      seen.add(taskKey);
      taskMatches.push({
        kind: 'task',
        checked: Boolean(task.completed),
        sort: sortValue(task.scheduled ?? task.due),
        label: taskLabel,
        path: pagePath,
        meta: page.file.name
      });
    }
    if (taskMatches.length > 0) {
      items.push(...taskMatches);
      continue;
    }
    if (pagePath === current.file.path) continue;
    if (normalizeDay(page.scheduled) !== dayKey) continue;
    if (collectTags(page).has('dailynote')) continue;
    const noteKey = `note:${pagePath}`;
    if (seen.has(noteKey)) continue;
    seen.add(noteKey);
    items.push({
      kind: 'note',
      checked: terminalStatuses.has(String(page.status ?? '').trim().toLowerCase()) || page.checklistDone === true,
      sort: sortValue(page.scheduled),
      label: page.file.name,
      path: pagePath,
      meta: page.scheduled ? String(page.scheduled) : ''
    });
  }
  items.sort((a, b) => a.sort - b.sort || Number(a.checked) - Number(b.checked) || a.label.localeCompare(b.label));
  if (items.length === 0) {
    dv.paragraph('Nothing scheduled for this day.');
  } else {
    const list = dv.container.createEl('ul', { cls: 'contains-task-list' });
    for (const item of items) {
      const row = list.createEl('li', { cls: 'task-list-item' });
      const checkbox = row.createEl('input', { type: 'checkbox', cls: 'task-list-item-checkbox' });
      checkbox.checked = item.checked;
      checkbox.disabled = true;
      const label = row.createEl('a', { cls: 'internal-link', text: item.label || item.path });
      label.href = item.path;
      label.addEventListener('click', openFile(item.path));
      if (item.meta) {
        const meta = row.createSpan();
        meta.textContent = ` - ${item.meta}`;
        meta.style.opacity = '0.7';
      }
    }
  }
}
